import { BaseActivePersona } from "../../base.ts";
import type { AuditRule, StrategicFinding, AuditFinding, HealingResult, ProjectContext } from "../../base.ts";

/**
 * 📊 Dr. Metric — PhD in TypeScript Data Telemetry & Logging
 * Generated by Sovereign Forge.
 */
export class MetricPersona extends BaseActivePersona {
    constructor(projectRoot: string | undefined = undefined) {
        super(projectRoot);
        this.id = "metric";
        this.name = "Metric";
        this.emoji = "📊";
        this.role = "PhD Observability Engineer";
        this.phd_identity = "TypeScript Data Telemetry & Logging";
        this.stack = "TypeScript";
        this.healingPrompt = "Fix the following metrics or KPI engineering issue. Correct metric calculations and ensure dimensional accuracy. Return ONLY the corrected code or a specific diff.";
    }

    override async execute(context: ProjectContext): Promise<(AuditFinding | StrategicFinding)[]> {
        this.setContext(context);
        if (this.healingPrompt) {
            const { findings } = await this.auditAndHeal();
            return findings;
        }
        const findings = await this.performAudit();
        return findings;
    }

    override getAuditRules(): { extensions: string[]; rules: AuditRule[] } {
        return {
            extensions: [".ts",".tsx"],
            rules: [
          {
                    "regex": "console\\.log\\(",
                    "issue": "Cegueira: console.log em produção — use logger estruturado.",
                    "severity": "high"
          },
          {
                    "regex": "console\\.error\\(",
                    "issue": "Telemetria Fraca: console.error sem contexto estruturado.",
                    "severity": "medium"
          },
          {
                    "regex": "catch\\s*\\([^)]*\\)\\s*\\{\\s*\\}",
                    "issue": "Cegueira Total: catch vazio engole erros silenciosamente.",
                    "severity": "critical"
          },
          {
                    "regex": "catch\\s*\\([^)]*\\)\\s*\\{[^}]*console\\.log",
                    "issue": "Telemetria Informal: Erro logado via console em vez de logger.",
                    "severity": "medium"
          }
]
        };
    }

    public override async performAudit(): Promise<AuditFinding[]> {
        this.startMetrics();
        
        const allFindings: AuditFinding[] = [];
        const files = Object.keys(this.contextData);
        
        for (const file of files) {
            const results = await this.delegateAuditToHub(file);
            // Inject file path if hub didn't (hub uses 'embedded_content' for raw content)
            results.forEach(f => {
                if (f.file === "embedded_content") f.file = file;
                allFindings.push(f);
            });
        }
        
        this.endMetrics(allFindings.length);
        return allFindings;
    }

    public override async reasonAboutObjective(objective: string, file: string, context: string): Promise<StrategicFinding | null> {
        return await super.reasonAboutObjective(objective, file, context);
    }

    override selfDiagnostic(): any {
        return { status: "Soberano", score: 100, details: "Módulo Metric operando com paridade total via Forge." };
    }

    override getSystemPrompt(): string {
        return `Você é o Dr. Metric, PhD em TypeScript Data Telemetry & Logging. Sua missão é garantir a excelência via governança PhD.`;
    }
}
